+void AutowareScoredCandidateTrajectoriesDisplay::onTopicChanged()
+{
+  // Automatically subscribe when topic changes
+  // This matches standard RViz behavior where topic selection enables visualization
+  if (this->isEnabled()) {
+    this->subscribe();
+  }
+}
